[FormDataSourceEventHandler(formDataSourceStr(LedgerJournalTransAsset, LedgerJournalTrans), FormDataSourceEventType::Activated)]
public static void LedgerJournalTrans_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun formRun = sender.formRun();

    FormStringControl paymentControl = formRun.control(formRun.controlId("LedgerJournalTrans_Payment")) as FormStringControl;

    if (paymentControl)
    {

        paymentControl.mandatory(false);
    }
}
